CREATE TABLE categories (id SERIAL PRIMARY KEY, name TEXT UNIQUE NOT NULL); CREATE TABLE staff (id SERIAL PRIMARY KEY, login TEXT UNIQUE NOT NULL, full_name TEXT NOT NULL); CREATE TABLE products (id SERIAL PRIMARY KEY, name TEXT NOT NULL, description TEXT, price DECIMAL(10,2), category_id INTEGER REFERENCES categories(id), images TEXT[], code TEXT, stock BOOLEAN DEFAULT true, created_at TIMESTAMP WITH TIME ZONE DEFAULT NOW()); INSERT INTO staff (login, full_name) VALUES ('andre', 'André Silva'); INSERT INTO categories (name) VALUES ('Utilidades'), ('Eletrônicos'), ('Cozinha');